func investSecurityTypeLabel(v interface{}) string {
	if s, ok := v.(string); ok && s != "" {
		return s
	}
	return "other"
}

func investSecurityTypeColor(v interface{}) string {
	colorMap := map[string]string{
		"equity":       "#6366f1",
		"etf":          "#60a5fa",
		"mutual fund":  "#c084fc",
		"fixed income": "#34d399",
		"cash":         "#4ade80",
		"derivative":   "#fb923c",
		"other":        "#64748b",
	}
	label := investSecurityTypeLabel(v)
	if c, ok := colorMap[label]; ok {
		return c
	}
	return colorMap["other"]
}

func investFormatMonth(s string) string {
	t, err := time.Parse("2006-01", s)
	if err != nil {
		return s
	}
	return t.Format("Jan 2006")
}

func investMonthCount(months []MonthFlow) string {
	n := len(months)
	if n == 1 {
		return "1"
	}
	return fmt.Sprintf("%d", n)
}

